-- ----------------------------
-- Table structure for monitoring_station
-- ----------------------------
DROP TABLE IF EXISTS `monitoring_station`;
CREATE TABLE `monitoring_station`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `station_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '站点名称',
  `longitude` decimal(10, 6) NOT NULL COMMENT '经度',
  `latitude` decimal(10, 6) NOT NULL COMMENT '纬度',
  `station_type` enum('river','lake','reservoir','monitoring') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '站点类型',
  `primary_mode` enum('flood','drought','both') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '站点主要模式（可选）',
  `current_value` decimal(10, 3) NOT NULL COMMENT '当前值（水位m 或 湿度% 等）',
  `value_unit` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'm' COMMENT '单位：m、% 等',
  `value_record_time` datetime NOT NULL COMMENT '数据采集时间（核心排序字段）',
  `alert_threshold` decimal(10, 3) NULL DEFAULT NULL COMMENT '警戒阈值',
  `guarantee_threshold` decimal(10, 3) NULL DEFAULT NULL COMMENT '保证阈值',
  `flood_risk` enum('extreme','high','medium','low','safe') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'safe',
  `drought_risk` enum('extreme','high','medium','low','safe') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'safe',
  `trend` enum('up','down','stable') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '趋势',
  `affected_area` decimal(12, 2) NULL DEFAULT 0.00 COMMENT '影响面积（km²）',
  `is_active` tinyint(1) NULL DEFAULT 1 COMMENT '是否启用',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_station_time`(`station_name` ASC, `value_record_time` ASC) USING BTREE,
  INDEX `idx_time_desc_name`(`value_record_time` DESC, `station_name` ASC) USING BTREE,
  INDEX `idx_station_name`(`station_name` ASC) USING BTREE,
  INDEX `idx_location`(`longitude` ASC, `latitude` ASC) USING BTREE,
  INDEX `idx_primary_mode`(`primary_mode` ASC) USING BTREE,
  INDEX `idx_active`(`is_active` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8773 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '水文监测站点历史数据表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of monitoring_station
-- ----------------------------

-- ----------------------------
-- Table structure for monitoring_station_history
-- ----------------------------
DROP TABLE IF EXISTS `monitoring_station_history`;
CREATE TABLE `monitoring_station_history`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `station_id` bigint NOT NULL COMMENT '站点ID（引用monitoring_station.id）',
  `record_date` datetime NOT NULL COMMENT '记录日期',
  `value_unit` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '值单位（m 或 %），便于区分水位/湿度',
  `is_warning` tinyint(1) NOT NULL DEFAULT 0 COMMENT '当日是否警戒(1:是, 0:否)',
  `current_value` decimal(10, 3) NOT NULL COMMENT '当前值',
  `flood_risk` enum('extreme','high','medium','low','safe') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '防汛风险等级（仅水位记录填写）',
  `drought_risk` enum('extreme','high','medium','low','safe') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '抗旱风险等级（仅湿度记录填写）',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_station_date`(`station_id` ASC, `record_date` ASC) USING BTREE,
  INDEX `idx_date`(`record_date` ASC) USING BTREE,
  INDEX `idx_warning`(`is_warning` ASC) USING BTREE,
  INDEX `idx_unit_risk`(`value_unit` ASC, `flood_risk` ASC, `drought_risk` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8773 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '监测站每日历史快照表（支持双模式区分）' ROW_FORMAT = Dynamic;

