-- ----------------------------
-- View structure for v_active_warnings
-- ----------------------------
DROP VIEW IF EXISTS `v_active_warnings`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_active_warnings` AS select `w`.`id` AS `id`,`w`.`station_id` AS `station_id`,`w`.`warning_type` AS `warning_type`,`w`.`warning_level` AS `warning_level`,`w`.`parameter` AS `parameter`,`w`.`value` AS `value`,`w`.`threshold` AS `threshold`,`w`.`description` AS `description`,`w`.`warning_time` AS `warning_time`,`w`.`status` AS `status`,`w`.`created_at` AS `created_at`,`s`.`name` AS `station_name`,`s`.`location` AS `location`,`s`.`quality_class` AS `quality_class` from (`warnings` `w` join `stations` `s` on((`w`.`station_id` = `s`.`id`))) where (`w`.`status` = 'active') order by (case `w`.`warning_level` when 'serious' then 1 when 'warning' then 2 when 'caution' then 3 else 4 end),`w`.`created_at` desc;

-- ----------------------------
-- View structure for v_station_history
-- ----------------------------
DROP VIEW IF EXISTS `v_station_history`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_station_history` AS select `monitoring_data`.`station_id` AS `station_id`,cast(`monitoring_data`.`data_time` as date) AS `date`,avg(`monitoring_data`.`ph`) AS `avg_pH`,avg(`monitoring_data`.`dissolved_oxygen`) AS `avg_DO`,avg(`monitoring_data`.`cod`) AS `avg_COD`,avg(`monitoring_data`.`ammonia_nitrogen`) AS `avg_NH3N`,avg(`monitoring_data`.`water_level`) AS `avg_level`,max(`monitoring_data`.`water_level`) AS `max_level`,min(`monitoring_data`.`water_level`) AS `min_level`,count(0) AS `data_count` from `monitoring_data` where ((`monitoring_data`.`is_predicted` = false) and (`monitoring_data`.`data_time` >= (curdate() - interval 30 day))) group by `monitoring_data`.`station_id`,cast(`monitoring_data`.`data_time` as date);

-- ----------------------------
-- View structure for v_station_latest
-- ----------------------------
DROP VIEW IF EXISTS `v_station_latest`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_station_latest` AS select `s`.`id` AS `id`,`s`.`code` AS `code`,`s`.`name` AS `name`,`s`.`type` AS `type`,`s`.`location` AS `location`,`s`.`river` AS `river`,`s`.`longitude` AS `longitude`,`s`.`latitude` AS `latitude`,`s`.`water_quality` AS `water_quality`,`s`.`quality_class` AS `quality_class`,`s`.`status` AS `status`,`s`.`trend` AS `trend`,`s`.`tags` AS `tags`,`s`.`icon` AS `icon`,`s`.`color` AS `color`,`s`.`created_at` AS `created_at`,`s`.`updated_at` AS `updated_at`,`md`.`data_time` AS `latest_time`,`md`.`water_level` AS `current_level`,`md`.`water_quality_category` AS `current_quality`,`md`.`ph` AS `pH`,`md`.`dissolved_oxygen` AS `dissolved_oxygen`,`md`.`cod` AS `COD`,`md`.`ammonia_nitrogen` AS `ammonia_nitrogen`,(select count(0) from `warnings` `w` where ((`w`.`station_id` = `s`.`id`) and (`w`.`status` = 'active'))) AS `active_warnings` from (`stations` `s` left join `monitoring_data` `md` on((`s`.`id` = `md`.`station_id`))) where (`md`.`data_time` = (select max(`monitoring_data`.`data_time`) from `monitoring_data` where ((`monitoring_data`.`station_id` = `s`.`id`) and (`monitoring_data`.`is_predicted` = false))));

SET FOREIGN_KEY_CHECKS = 1;
